#include <zephyr/types.h>
#include <zephyr/syscall.h>
#include <zephyr/privilege.h>

#define USER_TASK_PRIORITY 5
#define ADMIN_TASK_PRIORITY 10

struct task {
    int id;
    char name[32];
};

struct user_task {
    struct task task;
    bool is_admin;
};

struct admin_task {
    struct task task;
    bool can_write_flash;
    bool can_modify_system_config;
};

void user_task(void *args) {
    struct user_task *user = (struct user_task *) args;
    if (!user->is_admin) {
        // Request admin operation
        syscall_request_privilege(SYSCALL_PRIVILEGE_ADMIN);
        if (syscall_has_privilege(SYSCALL_PRIVILEGE_ADMIN)) {
            // Perform admin operation
            printf("Admin task: %s\n", user->task.name);
        } else {
            // Fallback to user-only operation
            printf("User task: %s\n", user->task.name);
        }
    } else {
        // Perform admin operation
        printf("Admin task: %s\n", user->task.name);
    }
}

void admin_task(void *args) {
    struct admin_task *admin = (struct admin_task *) args;
    if (admin->can_write_flash) {
        // Write to flash memory
        printf("Admin task: Writing to flash\n");
    }
    if (admin->can_modify_system_config) {
        // Modify system config
        printf("Admin task: Modifying system config\n");
    }
}

int main(void) {
    struct user_task user1 = { .id = 1, .name = "User 1", .is_admin = false };
    struct admin_task admin1 = { .id = 1, .name = "Admin 1", .can_write_flash = true, .can_modify_system_config = true };
    struct user_task user2 = { .id = 2, .name = "User 2", .is_admin = false };
    struct admin_task admin2 = { .id = 2, .name = "Admin 2", .can_write_flash = true, .can_modify_system_config = true };

    k_thread_create(&user1.task, user_task, &user1, USER_TASK_PRIORITY, NULL);
    k_thread_create(&admin1.task, admin_task, &admin1, ADMIN_TASK_PRIORITY, NULL);
    k_thread_create(&user2.task, user_task, &user2, USER_TASK_PRIORITY, NULL);
    k_thread_create(&admin2.task, admin_task, &admin2, ADMIN_TASK_PRIORITY, NULL);

    return 0;
}